// Determine mode based on day of week
// Sunday = 0, Friday = 5
const now = new Date();
const dayOfWeek = now.getDay();

let mode = 'planning';
if (dayOfWeek === 5) {
  mode = 'recap';
} else if (dayOfWeek === 0) {
  mode = 'planning';
}

// Get ISO week number for dedupe key
const getWeekNumber = (d) => {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dayNum = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  return Math.ceil((((date - yearStart) / 86400000) + 1) / 7);
};

const weekNumber = getWeekNumber(now);
const year = now.getFullYear();
const weekKey = `${year}-W${String(weekNumber).padStart(2, '0')}`;

return [{
  json: {
    mode: mode,
    weekKey: weekKey,
    timestamp: now.toISOString()
  }
}];

// Build Weekly Focus Review task description from AI analysis
const analysisResult = $json.data;
const modeData = $('Determine Mode').first().json;
const mode = modeData.mode;
const weekKey = modeData.weekKey;

// Format date for task title
const now = new Date();
const dateFormatted = now.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

// Build markdown description
let description = `## This Week's Focus\n${analysisResult.summary}\n\n`;

// Add suggested actions section
if (analysisResult.suggestions && analysisResult.suggestions.length > 0) {
  description += `## Suggested Actions\n`;
  analysisResult.suggestions.forEach((suggestion, i) => {
    const confidence = suggestion.confidence ? ` (${suggestion.confidence}% confidence)` : '';
    description += `${i + 1}. **${suggestion.title}**${confidence}\n`;
    if (suggestion.description) {
      description += `   ${suggestion.description}\n`;
    }
    description += `\n`;
  });
}

// Add patterns section
if (analysisResult.patterns && analysisResult.patterns.length > 0) {
  description += `## Patterns Noticed\n`;
  analysisResult.patterns.forEach(pattern => {
    const severityEmoji = pattern.severity === 'high' ? '🔴' : pattern.severity === 'medium' ? '🟡' : '🟢';
    description += `${severityEmoji} **${pattern.type}**: ${pattern.description}\n`;
    if (pattern.affected_items && pattern.affected_items.length > 0) {
      description += `   Affected: ${pattern.affected_items.join(', ')}\n`;
    }
    description += `\n`;
  });
}

// Add last week review section (for Friday recap)
if (analysisResult.last_week_review) {
  description += `## Last Week Review\n${analysisResult.last_week_review}\n`;
}

return [{
  json: {
    taskTitle: `Weekly Focus Review - ${dateFormatted}`,
    taskDescription: description,
    dedupeKey: `weekly_focus:${weekKey}`,
    mode: mode,
    weekKey: weekKey,
    suggestions: analysisResult.suggestions || [],
    suggestionCount: analysisResult.suggestions ? analysisResult.suggestions.length : 0
  }
}];

// Prepare AI suggestions for insertion
const taskData = $('Build Task Content').first().json;
const suggestions = taskData.suggestions || [];
const weekKey = taskData.weekKey;

// Filter suggestions that should create new tasks
// Only include suggestions of type 'new_task'
const newTaskSuggestions = suggestions.filter(s => s.type === 'new_task');

if (newTaskSuggestions.length === 0) {
  return [{
    json: {
      hasSuggestions: false,
      message: 'No new task suggestions to create'
    }
  }];
}

// Return each suggestion as a separate item for the loop
return newTaskSuggestions.map((suggestion, index) => ({
  json: {
    hasSuggestions: true,
    title: suggestion.title,
    description: suggestion.description || '',
    priority: suggestion.priority || 'normal',
    dueDate: suggestion.due_date || null,
    aiConfidence: suggestion.confidence || null,
    reasoning: suggestion.reasoning || null,
    dedupeKey: `ai_suggestion:${weekKey}:${index}`,
    weekKey: weekKey
  }
}));

// Count created suggestions from all items
const allItems = $input.all();
let createdCount = 0;
let skippedCount = 0;

allItems.forEach(item => {
  if (item.json.id) {
    createdCount++;
  } else if (item.json.hasSuggestions === false) {
    // No suggestions to create
  } else {
    skippedCount++; // Duplicate, skipped by ON CONFLICT DO NOTHING
  }
});

const modeData = $('Determine Mode').first().json;
const taskCreated = $('Create Weekly Focus Task').first().json;

return [{
  json: {
    success: true,
    mode: modeData.mode,
    weekKey: modeData.weekKey,
    weeklyFocusTaskId: taskCreated.id,
    weeklyFocusTaskTitle: taskCreated.title,
    suggestionsCreated: createdCount,
    suggestionsSkipped: skippedCount
  }
}];

